"use strict";(self.webpackChunkhell_saati=self.webpackChunkhell_saati||[]).push([["266"],{6164(a){a.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"category","label":"I. Giri\u015F","collapsed":true,"items":[{"type":"link","href":"/docs/hs00","label":"Olimpiada m\xfchitin\u0259 giri\u015F, datatipl\u0259r v\u0259 d\u0259yi\u015F\u0259nl\u0259r","docId":"hs00","unlisted":false},{"type":"link","href":"/docs/hs01","label":"Compiler, Code Editorlar v\u0259 onlar\u0131n y\xfckl\u0259nm\u0259 qaydas\u0131. Kodu compile etm\u0259k.","docId":"hs01","unlisted":false}],"collapsible":true},{"type":"category","label":"II. Proqramla\u015Fd\u0131rma \u0259saslar\u0131","collapsed":true,"items":[{"type":"link","href":"/docs/hs02","label":"\u015E\u0259rt operatorlar\u0131","docId":"hs02","unlisted":false},{"type":"link","href":"/docs/hs03","label":"D\xf6vrl\u0259r: for v\u0259 while","docId":"hs03","unlisted":false},{"type":"link","href":"/docs/hs04","label":"\u0130\xe7-i\xe7\u0259 d\xf6vrl\u0259r","docId":"hs04","unlisted":false}],"collapsible":true},{"type":"category","label":"III. Massivl\u0259r v\u0259 funksiyalar","collapsed":true,"items":[{"type":"link","href":"/docs/hs05","label":"Massivl\u0259r: \u0259saslar","docId":"hs05","unlisted":false},{"type":"link","href":"/docs/hs06","label":"Massiv \xfcz\u0259rind\u0259 \u0259m\u0259liyyatlar","docId":"hs06","unlisted":false},{"type":"link","href":"/docs/hs07","label":"Massivl\u0259rl\u0259 i\u015F","docId":"hs07","unlisted":false},{"type":"link","href":"/docs/hs08","label":"Funksiyalar","docId":"hs08","unlisted":false},{"type":"link","href":"/docs/hs09","label":"Simvollar v\u0259 stringl\u0259r","docId":"hs09","unlisted":false}],"collapsible":true},{"type":"category","label":"IV. Riyaziyyat, I/O v\u0259 \xfcsullar","collapsed":true,"items":[{"type":"link","href":"/docs/hs10","label":"Sad\u0259 riyaziyyat","docId":"hs10","unlisted":false},{"type":"link","href":"/docs/hs11","label":"2D massivl\u0259r","docId":"hs11","unlisted":false},{"type":"link","href":"/docs/hs12","label":"S\xfcr\u0259tli I/O v\u0259 format","docId":"hs12","unlisted":false},{"type":"link","href":"/docs/hs13","label":"Sad\u0259 s\u0131ralamalar","docId":"hs13","unlisted":false},{"type":"link","href":"/docs/hs14","label":"M\u0259s\u0259l\u0259 oxuma v\u0259 debugging","docId":"hs14","unlisted":false}],"collapsible":true},{"type":"category","label":"V. STL","collapsed":true,"items":[{"type":"link","href":"/docs/hs15","label":"STL: vector","docId":"hs15","unlisted":false},{"type":"link","href":"/docs/hs16","label":"Stack, queue v\u0259 deque","docId":"hs16","unlisted":false},{"type":"link","href":"/docs/hs17","label":"sort() v\u0259 comparator-lar","docId":"hs17","unlisted":false},{"type":"link","href":"/docs/hs18","label":"Set v\u0259 map","docId":"hs18","unlisted":false},{"type":"link","href":"/docs/hs19","label":"Heap v\u0259 priority queue","docId":"hs19","unlisted":false},{"type":"link","href":"/docs/hs20","label":"Binary search","docId":"hs20","unlisted":false}],"collapsible":true},{"type":"category","label":"VI. Axtar\u0131\u015F, rekursiya v\u0259 DP","collapsed":true,"items":[{"type":"link","href":"/docs/hs21","label":"Tam axtar\u0131\u015F (brute force)","docId":"hs21","unlisted":false},{"type":"link","href":"/docs/hs22","label":"Rekursiya v\u0259 backtracking","docId":"hs22","unlisted":false},{"type":"link","href":"/docs/hs23","label":"Memoization v\u0259 1D DP","docId":"hs23","unlisted":false},{"type":"link","href":"/docs/hs24","label":"Prefix sums","docId":"hs24","unlisted":false},{"type":"link","href":"/docs/hs25","label":"Two pointers","docId":"hs25","unlisted":false}],"collapsible":true},{"type":"category","label":"VII. Greedy, h\u0259nd\u0259s\u0259 v\u0259 hash","collapsed":true,"items":[{"type":"link","href":"/docs/hs26","label":"H\u0259nd\u0259s\u0259: intervallar, d\xfczbucaql\u0131lar","docId":"hs26","unlisted":false},{"type":"link","href":"/docs/hs27","label":"Greedy alqoritml\u0259r","docId":"hs27","unlisted":false},{"type":"link","href":"/docs/hs28","label":"GCD, LCM v\u0259 sad\u0259 \u0259d\u0259dl\u0259r","docId":"hs28","unlisted":false},{"type":"link","href":"/docs/hs29","label":"Hashing: unordered set v\u0259 map","docId":"hs29","unlisted":false}],"collapsible":true}]},"docs":{"hs00":{"id":"hs00","title":"Olimpiada m\xfchitin\u0259 giri\u015F, datatipl\u0259r v\u0259 d\u0259yi\u015F\u0259nl\u0259r","description":"Salam, m\u0259n \u018Fli S\xfcleymanzad\u0259. Respublika \u0130nformatika Olimpiadalar\u0131na son 10-cu sinifin ortalar\u0131nda ba\u015Flama\u011F\u0131ma baxmayaraq 11-ci sinifd\u0259 g\xfcm\xfc\u015F medal qazand\u0131m. Bununla yana\u015F\u0131, bir s\u0131ra respublika(RM 90, Iostream CUP) medal qazanmaq v\u0259 beyn\u0259lxalq(APIO 2025 v\u0259 APIO 2026) olimpiadalarda i\u015Ftirak etm\u0259k \u015Fans\u0131m oldu. Bu yolda \xe7ox \xe7\u0259tinlikl\u0259rim oldu, zaman-zaman gec\u0259l\u0259rl\u0259 yuxusuz qal\u0131b h\u0259m m\u0259kt\u0259b tap\u015F\u0131r\u0131qlar\u0131m\u0131, h\u0259m d\u0259 olimpiada haz\u0131rl\u0131\u011F\u0131m\u0131 davam etdirm\u0259li oldum. Lakin, \xe7\u0259kdiyim \u0259ziyy\u0259tin qar\u015F\u0131l\u0131\u011F\u0131n\u0131 ald\u0131m v\u0259 ADA Universitetind\u0259 pulsuz t\u0259hsil almaq haqq\u0131 qazand\u0131m.","sidebar":"tutorialSidebar"},"hs01":{"id":"hs01","title":"Compiler, Code Editorlar v\u0259 onlar\u0131n y\xfckl\u0259nm\u0259 qaydas\u0131. Kodu compile etm\u0259k.","description":"Compileri yazd\u0131\u011F\u0131n\u0131z kod par\xe7as\u0131n\u0131 ma\u015F\u0131n dilin\u0259 - komp\xfcterin anlaya bil\u0259c\u0259yi dil\u0259 \xe7evir\u0259n t\u0259rc\xfcm\u0259\xe7i kimi d\xfc\u015F\xfcn\u0259 bil\u0259rsiniz.","sidebar":"tutorialSidebar"},"hs02":{"id":"hs02","title":"\u015E\u0259rt operatorlar\u0131","description":"Proqramlar yaln\u0131z yuxar\u0131dan a\u015Fa\u011F\u0131 s\u0259tir-s\u0259tir i\u015Fl\u0259s\u0259ydi, komp\xfcter sad\u0259 kalkulyatordan f\u0259rql\u0259nm\u0259zdi. Proqram\u0131 \\"a\u011F\u0131ll\u0131\\" ed\u0259n \u0259sas al\u0259t \u015F\u0259rt operatorlar\u0131d\u0131r. \u015E\u0259rt operatorlar\u0131 m\xfc\u0259yy\u0259n \u015F\u0259rt \xf6d\u0259ndikd\u0259 bir i\u015Fi, \xf6d\u0259nm\u0259dikd\u0259 ba\u015Fqa i\u015Fi g\xf6rm\u0259y\u0259 k\xf6m\u0259k edir.","sidebar":"tutorialSidebar"},"hs03":{"id":"hs03","title":"D\xf6vrl\u0259r: for v\u0259 while","description":"Komp\xfcterin \u0259sl g\xfcc\xfc eyni \u0259m\u0259liyyat\u0131 milyonlarla d\u0259f\u0259 yorulmadan t\u0259krarlamas\u0131ndad\u0131r. Bunu d\xf6vrl\u0259r (loops) edir.","sidebar":"tutorialSidebar"},"hs04":{"id":"hs04","title":"\u0130\xe7-i\xe7\u0259 d\xf6vrl\u0259r","description":"D\xf6vr\xfcn i\xe7ind\u0259 d\xf6vr yazmaq CP-d\u0259 \u0259n \xe7ox istifad\u0259 olunan konstruksiyalardan biridir. Matrisl\u0259r, fiqur \xe7ap\u0131, b\xfct\xfcn c\xfctl\u0259rin yoxlanmas\u0131, sad\u0259 \u0259d\u0259d testi v\u0259 s. m\xf6vzularda i\xe7-i\xe7\u0259 d\xf6vrl\u0259r\u0259 tez tez ehtiyac duyulur. Bu d\u0259rsd\u0259:","sidebar":"tutorialSidebar"},"hs05":{"id":"hs05","title":"Massivl\u0259r: \u0259saslar","description":"\u0130ndiy\u0259 q\u0259d\u0259r \u0259d\u0259dl\u0259ri oxuyub d\u0259rhal emal edirdik. Amma \xe7ox vaxt veril\u0259nl\u0259ri yadda saxlamaq laz\u0131m olur: \\"\u0259d\u0259dl\u0259ri oxu, sonra ax\u0131rdan \u0259vv\u0259l\u0259 \xe7ap et\\" kimi suallar\u0131 massivsiz etm\u0259k olmur.","sidebar":"tutorialSidebar"},"hs06":{"id":"hs06","title":"Massiv \xfcz\u0259rind\u0259 \u0259m\u0259liyyatlar","description":"Massivi oxuma\u011F\u0131 \xf6yr\u0259ndik; indi onun \xfcz\u0259rind\u0259 hesablamalar aparaq. Bu d\u0259rs CP-nin \\"vurma c\u0259dv\u0259li\\" kimidir. \xc7\xfcnki bu d\u0259rs ke\xe7\u0259c\u0259kl\u0259rimiz dem\u0259k olar ki, h\u0259r m\u0259s\u0259l\u0259nin alt m\u0259s\u0259l\u0259si kimi qar\u015F\u0131n\u0131za \xe7\u0131xa bil\u0259r.","sidebar":"tutorialSidebar"},"hs07":{"id":"hs07","title":"Massivl\u0259rl\u0259 i\u015F: reverse, shift, silm\u0259","description":"Bu d\u0259rsd\u0259 \xf6yr\u0259n\u0259c\u0259yik:","sidebar":"tutorialSidebar"},"hs08":{"id":"hs08","title":"Funksiyalar","description":"Kod b\xf6y\xfcd\xfckc\u0259 onu hiss\u0259l\u0259r\u0259 b\xf6lm\u0259k laz\u0131m g\u0259lir. Funksiya ad verilmi\u015F, t\u0259krar \xe7a\u011F\u0131r\u0131la bil\u0259n kod par\xe7as\u0131d\u0131r. Funksiyalardan daha az s\u0259hv, daha asan debug etm\u0259k v\u0259 daha s\xfcr\u0259tli kod yazmaq, y\u0259ni t\u0259krarlar\u0131n qar\u015F\u0131s\u0131n\u0131 almaq \xfc\xe7\xfcn istifad\u0259 olunur.","sidebar":"tutorialSidebar"},"hs09":{"id":"hs09","title":"Simvollar v\u0259 stringl\u0259r","description":"M\u0259tnl\u0259 i\u015Fl\u0259m\u0259k CP-nin b\xf6y\xfck hiss\u0259sidir. String simvollar massividir v\u0259 massivl\u0259 ox\u015Far formada i\u015Fl\u0259yir.","sidebar":"tutorialSidebar"},"hs10":{"id":"hs10","title":"Sad\u0259 riyaziyyat","description":"CP-d\u0259 \\"riyaziyyat\\" \xe7ox vaxt ali riyaziyyat deyil, sad\u0259c\u0259 tam b\xf6lm\u0259, qal\u0131q, yuvarlaqla\u015Fd\u0131rma v\u0259 overflow kimi anlay\u0131\u015Flard\u0131r. Bu d\u0259rsd\u0259 h\u0259min anlay\u0131\u015Flara n\u0259z\u0259r salacay\u0131q.","sidebar":"tutorialSidebar"},"hs11":{"id":"hs11","title":"2D massivl\u0259r","description":"C\u0259dv\u0259l, matris, oyun taxtas\u0131, labirint kimi hallar\u0131n ham\u0131s\u0131 iki \xf6l\xe7\xfcl\xfc massivl\u0259rdir. 2D massiv is\u0259 \\"massivl\u0259rin massividir\\": ai i-ci s\u0259tir, j-ci s\xfctun.","sidebar":"tutorialSidebar"},"hs12":{"id":"hs12","title":"S\xfcr\u0259tli I/O v\u0259 \xe7ap format\u0131","description":"B\u0259z\u0259n d\xfczg\xfcn alqoritm yaz\u0131rs\u0131n\u0131z, amma TLE al\u0131rs\u0131n\u0131z. Bu zaman s\u0259hv alqoritm yox, input/output-da olur.","sidebar":"tutorialSidebar"},"hs13":{"id":"hs13","title":"Sad\u0259 s\u0131ralama alqoritml\u0259ri","description":"S\u0131ralama CP-nin \u0259n fundamental \u0259m\u0259liyyat\u0131d\u0131r. Praktikada haz\u0131r sort() istifad\u0259 ed\u0259c\u0259yik, amma \u0259vv\u0259lc\u0259 s\u0131ralaman\u0131n nec\u0259 i\u015Fl\u0259diyini bilm\u0259k laz\u0131md\u0131r.","sidebar":"tutorialSidebar"},"hs14":{"id":"hs14","title":"M\u0259s\u0259l\u0259 oxuma, k\u0259nar hallar v\u0259 debugging","description":"Olimpiadada ballar \xe7ox vaxt bilik \xe7at\u0131\u015Fmazl\u0131\u011F\u0131ndan yox, \xfc\xe7 \u015Feyd\u0259n itir: m\u0259s\u0259l\u0259ni s\u0259hv oxumaq, k\u0259nar hal\u0131 unutmaq v\u0259 s\u0259hvi tapa bilm\u0259m\u0259k.","sidebar":"tutorialSidebar"},"hs15":{"id":"hs15","title":"STL: vector","description":"Buradan etibar\u0259n C++-\u0131n \u0259sl g\xfcc\xfcn\u0259 \u2014 STL-\u0259 (Standard Template Library) ke\xe7irik. STL \u2014 haz\u0131r, s\xfcr\u0259tli, s\u0131nanm\u0131\u015F data strukturlar v\u0259 alqoritml\u0259r kolleksiyas\u0131d\u0131r. \u0130lk v\u0259 \u0259n vacib \xfczv: vector \u2014 \xf6l\xe7\xfcs\xfc d\u0259yi\u015F\u0259 bil\u0259n massiv.","sidebar":"tutorialSidebar"},"hs16":{"id":"hs16","title":"Stack, queue v\u0259 deque","description":"Bu \xfc\xe7 struktur \u2014 elementl\u0259rin hans\u0131 ucdan girib-\xe7\u0131xd\u0131\u011F\u0131n\u0131 m\u0259hdudla\u015Fd\u0131ran siyah\u0131lard\u0131r. M\u0259hdudiyy\u0259t z\u0259iflik deyil, g\xfccd\xfcr: d\xfczg\xfcn struktur se\xe7il\u0259n m\u0259s\u0259l\u0259 \xf6z-\xf6z\xfcn\u0259 h\u0259ll olunur.","sidebar":"tutorialSidebar"},"hs17":{"id":"hs17","title":"sort() v\u0259 comparator-lar","description":"12-ci d\u0259rsd\u0259 s\u0131ralaman\u0131 \u0259l il\u0259 qurduq \u2014 O(n\xb2). \u0130ndi pe\u015F\u0259kar al\u0259t: STL-in sort() funksiyas\u0131 \u2014 O(n log n), n = 10\u2076-n\u0131 saniy\u0259nin onda birind\u0259 s\u0131ralay\u0131r. Bu d\u0259rsd\u0259n sonra s\u0131ralama sizin \xfc\xe7\xfcn bir s\u0259tirdir; \u0259sl m\xf6vzu \u2014 n\u0259y\u0259 g\xf6r\u0259 s\u0131ralama\u011F\u0131 t\u0259yin etm\u0259kdir.","sidebar":"tutorialSidebar"},"hs18":{"id":"hs18","title":"Set v\u0259 map","description":"Bu g\xfcn\u0259 q\u0259d\u0259r \\"bu element var, ya yox?\\" sual\u0131na massivl\u0259 d\xf6vr yaz\u0131b O(n)-d\u0259 cavab verirdik. set v\u0259 map bu suala O(log n)-d\u0259 cavab verir \u2014 n = 10\u2075 \xfc\xe7\xfcn ~17 add\u0131m. Bu iki struktur STL-in \u0259n \xe7ox i\u015Fl\u0259n\u0259n al\u0259tl\u0259ridir.","sidebar":"tutorialSidebar"},"hs19":{"id":"hs19","title":"Heap v\u0259 priority queue","description":"Tez-tez bel\u0259 v\u0259ziyy\u0259t yaran\u0131r","sidebar":"tutorialSidebar"},"hs20":{"id":"hs20","title":"Binary search","description":"L\xfc\u011F\u0259td\u0259 s\xf6z axtaranda h\u0259r s\u0259hif\u0259ni bir-bir \xe7evirmirsiniz \u2014 ortadan a\xe7\u0131b \\"\u0259vv\u0259ld\u0259dir, ya sonra?\\" dey\u0259 yar\u0131ya b\xf6l\xfcrs\xfcn\xfcz. Binar axtar\u0131\u015F m\u0259hz budur: h\u0259r add\u0131mda axtar\u0131\u015F sah\u0259sini yar\u0131ya endirm\u0259k. 10\u2079 elementli sah\u0259 \u2014 c\u0259mi ~30 add\u0131m.","sidebar":"tutorialSidebar"},"hs21":{"id":"hs21","title":"Tam axtar\u0131\u015F (brute force)","description":"\u018Fn universal alqoritm","sidebar":"tutorialSidebar"},"hs22":{"id":"hs22","title":"Rekursiya v\u0259 backtracking","description":"Rekursiya \u2014 funksiyan\u0131n \xf6z-\xf6z\xfcn\xfc \xe7a\u011F\u0131rmas\u0131d\u0131r. \u0130lk bax\u0131\u015Fda q\u0259rib\u0259 g\xf6r\xfcn\xfcr, amma arxas\u0131nda sad\u0259 f\u0259ls\u0259f\u0259 var: b\xf6y\xfck m\u0259s\u0259l\u0259ni eyni formal\u0131 ki\xe7ik m\u0259s\u0259l\u0259y\u0259 \xe7evir, \u0259n ki\xe7ik hal\u0131 \u0259l il\u0259 h\u0259ll et. Rekursiyan\u0131 d\u0259rind\u0259n ba\u015Fa d\xfc\u015Fm\u0259k \u2014 DP, qraflar (DFS) v\u0259 a\u011Fac alqoritml\u0259rinin ham\u0131s\u0131na a\xe7ar verir.","sidebar":"tutorialSidebar"},"hs23":{"id":"hs23","title":"Memoization v\u0259 1D DP","description":"Ke\xe7\u0259n d\u0259rs fib(n)-in eksponensial b\xf6y\xfcd\xfcy\xfcn\xfc g\xf6rd\xfck H\u0259r alt m\u0259s\u0259l\u0259ni bir d\u0259f\u0259 h\u0259ll et, cavab\u0131n\u0131 saxla, t\u0259krar soru\u015Fulanda haz\u0131r\u0131ndan ver. Buna g\xf6r\u0259 d\u0259 DP olimpiadalar\u0131n b\u0259lk\u0259 d\u0259 \u0259n vacib m\xf6vzusudur.","sidebar":"tutorialSidebar"},"hs24":{"id":"hs24","title":"Prefix sums","description":"Massiv verilir v\u0259 q d\u0259f\u0259 soru\u015Fulur: \\"a..b interval\u0131n\u0131n c\u0259mi ne\xe7\u0259dir?\\" H\u0259r sor\u011Fuda d\xf6vrl\u0259 c\u0259ml\u0259m\u0259k O(n  q) \u2014 n = q = 2  10\u2075 \xfc\xe7\xfcn 4  10\xb9\u2070 \u0259m\u0259liyyat, \xfcmidsiz. Prefix c\u0259ml\u0259ri h\u0259r sor\u011Funu O(1)*-\u0259 sal\u0131r. Bir haz\u0131rl\u0131q, sonsuz ucuz sor\u011Fu \u2014 CP-nin \u0259n sevimli barterl\u0259rind\u0259n.","sidebar":"tutorialSidebar"},"hs25":{"id":"hs25","title":"Two pointers","description":"O(n\xb2) d\xf6vr c\xfct\xfc \xe7ox vaxt bel\u0259 g\xf6r\xfcn\xfcr O(n\xb2) \u2192 O(n).","sidebar":"tutorialSidebar"},"hs26":{"id":"hs26","title":"H\u0259nd\u0259s\u0259: intervallar, d\xfczbucaql\u0131lar","description":"Olimpiada h\u0259nd\u0259s\u0259sinin giri\u015F qap\u0131s\u0131 \xfc\xe7bucaqlar deyil \u2014 oxlara paralel intervallar v\u0259 d\xfczbucaql\u0131lard\u0131r. Bu m\u0259s\u0259l\u0259l\u0259r d\xfcstur yox, diqq\u0259tli hal t\u0259hlili ist\u0259yir. Bu d\u0259rsd\u0259 koordinat m\xfcst\u0259visind\u0259 \u0259n \xe7ox \xe7\u0131xan \xfc\xe7 motivi \xf6yr\u0259nirik: interval k\u0259si\u015Fm\u0259si, d\xfczbucaql\u0131 k\u0259si\u015Fm\u0259si, hadis\u0259 \xfcsulu.","sidebar":"tutorialSidebar"},"hs27":{"id":"hs27","title":"Greedy alqoritml\u0259r","description":"Greedy (acg\xf6z) alqoritml\u0259r h\u0259r add\u0131mda indiki v\u0259ziyy\u0259t\u0259 g\xf6r\u0259 \u0259n yax\u015F\u0131 g\xf6r\xfcn\u0259n se\xe7imi etm\u0259kdir.","sidebar":"tutorialSidebar"},"hs28":{"id":"hs28","title":"GCD, LCM v\u0259 sad\u0259 \u0259d\u0259dl\u0259r","description":"\u018Fd\u0259dl\u0259r n\u0259z\u0259riyy\u0259si olimpiadalar\u0131n daimi qona\u011F\u0131d\u0131r. Bu d\u0259rsd\u0259 d\xf6rd t\u0259m\u0259l n\u0259z\u0259riyy\u0259: Evklid alqoritmi (GCD), sad\u0259lik yoxlamas\u0131, Eratosfen \u0259l\u0259yi v\u0259 s\xfcr\u0259tli q\xfcvv\u0259t\u0259 y\xfcks\u0259ltm\u0259 + mod arifmetikas\u0131 haqq\u0131nda dan\u0131\u015Facay\u0131q.","sidebar":"tutorialSidebar"},"hs29":{"id":"hs29","title":"Hashing: unordered set v\u0259 map","description":"Kamp\u0131n son h\u0259ll saat\u0131na xo\u015F g\u0259ldiniz. \u018Fvv\u0259lki d\u0259rsl\u0259rd\u0259 set v\u0259 map-in O(log n) oldu\u011Funu g\xf6rd\xfck. Hash c\u0259dv\u0259li eyni \u0259m\u0259liyyatlar\u0131 normal halda O(1)-\u0259 edir. Bu d\u0259rsd\u0259 unorderedset v\u0259 unorderedmap-in nec\u0259 i\u015Fl\u0259diyini, n\u0259 vaxt se\xe7ilm\u0259li oldu\u011Funu v\u0259 string hashing-in \u0259sas ideyas\u0131n\u0131 \xf6yr\u0259nirik.","sidebar":"tutorialSidebar"}}}}')}}]);